     0→#!/usr/bin/env node
     1→/**
     2→ * session-lifecycle-hook.mjs
     3→ * Handles SessionStart and SessionEnd events for trae-plugin-cc
     4→ */
     5→
     6→import { execSync } from 'child_process';
     7→import { existsSync, readdirSync, statSync, unlinkSync } from 'fs';
     8→import { join } from 'path';
     9→import { getPluginDir, getRunningJobs } from './job-utils.mjs';
    10→
    11→const CONFIG_FILE = '.trae/trae_config.yaml';
    12→
    13→function checkTraeCliInstalled() {
    14→  // Use execSync only with fixed commands, no user input
    15→  try {
    16→    execSync('which trae-cli', { stdio: 'ignore' });
    17→    return true;
    18→  } catch {
    19→    return false;
    20→  }
    21→}
    22→
    23→function checkTraeConfig() {
    24→  const configPath = join(process.cwd(), CONFIG_FILE);
    25→  return existsSync(configPath);
    26→}
    27→
    28→function cleanupStaleLogs() {
    29→  const pluginDir = getPluginDir();
    30→  if (!existsSync(pluginDir)) return;
    31→
    32→  const now = Date.now();
    33→  const sevenDays = 7 * 24 * 60 * 60 * 1000;
    34→
    35→  try {
    36→    const files = readdirSync(pluginDir);
    37→    const logs = files.filter(f => f.endsWith('.log'));
    38→
    39→    for (const logFile of logs) {
    40→      const logPath = join(pluginDir, logFile);
    41→      const mtime = statSync(logPath).mtimeMs;
    42→      if (now - mtime > sevenDays) {
    43→        try {
    44→          unlinkSync(logPath);
    45→          const pidFile = logFile.replace('.log', '.pid');
    46→          const pidPath = join(pluginDir, pidFile);
    47→          if (existsSync(pidPath)) unlinkSync(pidPath);
    48→        } catch {
    49→          // Ignore cleanup errors
    50→        }
    51→      }
    52→    }
    53→  } catch {
    54→    // Ignore errors
    55→  }
    56→}
    57→
    58→async function sessionStart() {
    59→  console.log('🔍 [Trae Plugin] Session Start Check');
    60→  console.log('─'.repeat(40));
    61→
    62→  const installed = checkTraeCliInstalled();
    63→  const hasConfig = checkTraeConfig();
    64→
    65→  if (installed && hasConfig) {
    66→    console.log('✅ trae-cli 已安装并配置');
    67→  } else {
    68→    if (!installed) {
    69→      console.log('⚠️  trae-cli 未安装');
    70→    }
    71→    if (!hasConfig) {
    72→      console.log('⚠️  配置文件不存在');
    73→    }
    74→    console.log('\n运行 /trae:setup 进行初始化');
    75→  }
    76→
    77→  const running = getRunningJobs();
    78→  if (running.length > 0) {
    79→    console.log(`📋 后台任务: ${running.length} 个运行中`);
    80→  }
    81→
    82→  console.log('─'.repeat(40));
    83→}
    84→
    85→async function sessionEnd() {
    86→  console.log('🔍 [Trae Plugin] Session End Cleanup');
    87→  console.log('─'.repeat(40));
    88→
    89→  cleanupStaleLogs();
    90→
    91→  const running = getRunningJobs();
    92→  if (running.length > 0) {
    93→    console.log(`⚠️  有 ${running.length} 个后台任务仍在运行:`);
    94→    for (const id of running) {
    95→      console.log(`   - ${id}`);
    96→    }
    97→    console.log('使用 /trae:status 查看状态');
    98→  } else {
    99→    console.log('✅ 无运行中的任务');
   100→  }
   101→
   102→  console.log('─'.repeat(40));
   103→}
   104→
   105→async function postReview() {
   106→  // Post-review hook - placeholder for tracking
   107→  process.exit(0);
   108→}
   109→
   110→// Main handler
   111→const hookType = process.argv[2];
   112→
   113→switch (hookType) {
   114→  case 'SessionStart':
   115→    sessionStart();
   116→    break;
   117→  case 'SessionEnd':
   118→    sessionEnd();
   119→    break;
   120→  case 'PostReview':
   121→    postReview();
   122→    break;
   123→  default:
   124→    console.error('Unknown hook type:', hookType);
   125→    process.exit(1);
