     0→import { spawn, ChildProcess } from 'child_process';
     1→import * as fs from 'fs';
     2→import * as path from 'path';
     3→import { AuthBridge } from './auth-bridge';
     4→
     5→export interface TraeTaskConfig {
     6→  prompt: string;
     7→  background?: boolean;
     8→  jsonOutput?: boolean;
     9→  yolo?: boolean;
    10→  allowedTools?: string[];
    11→  disallowedTools?: string[];
    12→  sessionId?: string;
    13→  resume?: string;
    14→  worktree?: string;
    15→  queryTimeout?: string;
    16→  bashToolTimeout?: string;
    17→  configOverrides?: Record<string, string>;
    18→}
