    20→export interface TraeTaskResult {
    21→  taskId: string;
    22→  output: string;
    23→  exitCode: number | null;
    24→  sessionId?: string;
    25→  duration: number;
    26→  jsonOutput?: any;
    27→}
    28→
    29→const PLUGIN_DIR = path.join(process.cwd(), '.claude-trae-plugin');
    30→
    31→function ensurePluginDir() {
    32→  if (!fs.existsSync(PLUGIN_DIR)) {
    33→    fs.mkdirSync(PLUGIN_DIR, { recursive: true });
    34→  }
    35→}
    36→
    37→export class TraeExecutor {
    38→  private authBridge: AuthBridge;
    39→
    40→  constructor() {
    41→    this.authBridge = new AuthBridge();
    42→  }
    43→
    44→  async execute(config: TraeTaskConfig): Promise<TraeTaskResult> {
    45→    ensurePluginDir();
    46→
    47→    const taskId = Date.now().toString();
    48→    const logFile = path.join(PLUGIN_DIR, `${taskId}.log`);
    49→    const pidFile = path.join(PLUGIN_DIR, `${taskId}.pid`);
    50→    const args = this.buildArgs(config);
    51→    const env = this.authBridge.buildSpawnEnv();
    52→    const startTime = Date.now();
    53→
    54→    if (config.background) {
    55→      return this.executeBackground(args, env, taskId, logFile, pidFile, startTime);
    56→    }
    57→
    58→    return this.executeForeground(args, env, taskId, logFile, pidFile, startTime, config.jsonOutput);
    59→  }
    60→
    61→  private buildArgs(config: TraeTaskConfig): string[] {
    62→    const args: string[] = [];
    63→
    64→    if (config.allowedTools) {
    65→      for (const tool of config.allowedTools) {
    66→        args.push('--allowed-tool', tool);
    67→      }
    68→    }
    69→
    70→    if (config.disallowedTools) {
    71→      for (const tool of config.disallowedTools) {
    72→        args.push('--disallowed-tool', tool);
